  tab$sampid <- this_samp
  names(tab)
  tab <- tab[,c(7,1,2,3,4,5)] # this time capture 'count' data
  names(tab) <- names(sfx.long.count)
  sfx.long.count <- rbind(sfx.long.count,tab)
  print(paste0("completed ",i," - sample ID: ",sampid[i]))
