# $ data_for_this_cpd: chr  NA NA NA NA ...
# $ p_val            : num  0.000575 0.478376 0.015075 0.015075 0.919333 ...
# $ kendall_tau      : num  -0.6995 -0.144 -0.4938 -0.4938 0.0206 ...
# $ trend_with_age   : chr  "Decreasing" NA "Decreasing" "Decreasing" ...
# $ trend_with_degrad: chr  "Increasing" NA "Increasing" "Increasing" ...

sel <- which(is.na(dat.test$p_val)) # empty

dat.test$p_adj_BH <- p.adjust(dat.test$p_val, method = "BH" )
hist(dat.test$p_adj_BH)


# extract sig results

sel.sigBH <- which(dat.test$p_adj_BH <= 0.05) # 2122
dat.test$sigBH <- NA
dat.test$sigBH[sel.sigBH] <- "sig"

sel.sig <- which(dat.test$p_val <= 0.05) # 2958

dat.test.sig <- dat.test[sel.sig, ]

dat.test.sig$minuslog10_p_val <- -log10(dat.test.sig$p_val)
plot(x = dat.test.sig$kendall_tau , y =dat.test.sig$minuslog10_p_val , xlab="Kendall tau", ylab="-log10(P-value)")

sel.sigBH <- which(dat.test.sig$sigBH == "sig")

