## PERMANOVA

# Calculate bray curtis distance matrix
set.seed(123)
bray <- phyloseq::distance(phy_in, method = "bray")
sampledf <- data.frame(sample_data(phy_in))
str(sampledf)
names(phy_in@sam_data)

# Adonis test
set.seed(123)
adonis2(bray ~ group , data = sampledf)
# Permutation test for adonis under reduced model
# Terms added sequentially (first to last)
# Permutation: free
# Number of permutations: 999
# 
# adonis2(formula = bray ~ group, data = sampledf)
#          Df SumOfSqs      R2      F Pr(>F)    
# group     1 0.017811 0.20222 20.785  0.001 ***
# Residual 82 0.070266 0.79778                  
# Total    83 0.088077 1.00000                  
# ---
# Signif. codes:  0 ‘***’ 0.001 ‘**’ 0.01 ‘*’ 0.05 ‘.’ 0.1 ‘ ’ 1

beta <- betadisper(bray, sampledf$group)
set.seed(123)
permutest(beta)
# Permutation test for homogeneity of multivariate dispersions
# Permutation: free
# Number of permutations: 999
# Response: Distances
#           Df    Sum Sq    Mean Sq      F N.Perm Pr(>F)
# Groups     1 0.0004794 0.00047942 1.8426    999  0.184
# Residuals 82 0.0213356 0.00026019  


## paper figure
cols.group <- c("Disturbed" = "#9e0142",
                "Natural" = "#3288bd")

p <- ggplot(data = p_df, aes(x = Axis.1, y = Axis.2, color = group))+
  ggtitle("Disturbed vs natural")+
  theme_classic()+
  geom_point()+
  xlab(x_lab) + ylab(y_lab)+
  scale_color_manual(values = cols.group, name = "Group") +
  annotate(geom="text_npc", npcx = "left", npcy = "top", label = "PERMANOVA:\nR^2 = 0.20, P = 0.001\nBeta-disp: P = 0.18", size = 2.8, lineheight=0.85 )+
  theme(
    panel.grid.major = element_blank(),
    legend.position = "bottom",
    legend.title = element_text(size = rel(0.85)),
    legend.text = element_text(size = rel(0.8), margin = margin(t = 0, r = 0, b = 0, l = 0, unit = "pt")),
