## PERMANOVA

# Calculate bray curtis distance matrix
set.seed(123)
bray <- phyloseq::distance(phy_in, method = "bray")
sampledf <- data.frame(sample_data(phy_in))
str(sampledf)
names(phy_in@sam_data)

# Adonis test
set.seed(123)
adonis2(bray ~ group , data = sampledf)
# Permutation test for adonis under reduced model
# Terms added sequentially (first to last)
# Permutation: free
# Number of permutations: 999
# 
# adonis2(formula = bray ~ group, data = sampledf)
#          Df  SumOfSqs      R2      F Pr(>F)    
# group     7 0.0073993 0.76198 10.061  0.001 ***
# Residual 22 0.0023114 0.23802                  
# Total    29 0.0097107 1.00000                  
# ---
# Signif. codes:  0 ‘***’ 0.001 ‘**’ 0.01 ‘*’ 0.05 ‘.’ 0.1 ‘ ’ 1

beta <- betadisper(bray, sampledf$group)
set.seed(123)
permutest(beta)
# Permutation test for homogeneity of multivariate dispersions
# Permutation: free
# Number of permutations: 999
# 
# Response: Distances
#           Df     Sum Sq    Mean Sq      F N.Perm Pr(>F)
# Groups     7 0.00014689 2.0984e-05 1.8314    999  0.145
# Residuals 22 0.00025207 1.1458e-05


