  dat.test.sig$OC_x[i] <- df.comp$OC_ratio[sel.cpd]
  dat.test.sig$HC_y[i] <- df.comp$HC_ratio[sel.cpd]
  dat.test.sig$NC_z[i] <- df.comp$NC_ratio[sel.cpd]
  
  print(paste0("completed ",i))
}

