  annotate(geom="text_npc", npcx = "right", npcy = "top", label = "PERMANOVA:\nR^2 = 0.56, P = 0.001\nBeta-disp: P = 0.09", size = 2.8, lineheight=0.85 )+
  guides(color = guide_legend(nrow=2, ncol=2, byrow=TRUE))+
