#### Wang veg succession - compound-wide scan, then B-H p-adjustment?
#-------------------------

# check for CPP trends with veg succession?
dat.cpd.collate <- readRDS("dat.cpd.collate-all-samps-cpp3d-ExtraData-wang-veg-succession-v8c.rds")
str(dat.cpd.collate)
# 'data.frame':	125235 obs. of  6 variables:
# $ cpd_id      : chr  "cpd25681" "cpd02597" "cpd24620" "cpd00001" ...
# $ sample      : chr  "SRR28123688" "SRR28123688" "SRR28123688" "SRR28123688" ...
# $ cpd_rel_abun: num  0.000136 0.021326 0.000532 4.965484 0.017564 ...
# $ log10_abun  : num  -3.865 -1.671 -3.274 0.696 -1.755 ...
# $ group       : Ord.factor w/ 5 levels "1"<"5"<"20"<"35"<..: 4 4 4 4 4 4 4 4 4 4 ...
# $ ord_group   : int  4 4 4 4 4 4 4 4 4 4 ...

length(unique(dat.cpd.collate$sample)) # 15

data_in <- dat.cpd.collate
dim(data_in) # 125235      6

unique(data_in$group)
# [1] 35 20 5  1  50
# Levels: 1 < 5 < 20 < 35 < 50


dat.test <- data.frame(cpd = unique(data_in$cpd_id), data_for_this_cpd=NA , p_val = NA, kendall_tau = NA, trend_with_age = NA, trend_with_degrad = NA )


for (i in 1:dim(dat.test)[1]) {
  #i<-1
  this_cpd <- dat.test$cpd[i]
  sel <- which(data_in$cpd_id == this_cpd)
  # Kendall Tau correlation
  
  x = data_in$ord_group[sel]
  y = data_in$log10_abun[sel]
  df = as.data.frame(cbind(x,y))
  sel.ok = which(complete.cases(df)==TRUE)
  df = df[sel.ok, ]
  if (sd(df$y)==0 & length(unique(df$y))==1 & unique(df$y)[1]==min(df$y)) {
    # disqualified: if they were all zeros before zero-replacement
    dat.test$data_for_this_cpd[i] <- "disqualified"
    
  } else if ( length(which(df$y > min(df$y))) < 0.25*length(sel) ) { # i.e. 3.75 ; 3 or less
    # low data: if non-zero cases do not comprise at least a replicate / a quarter of available scenario data
    dat.test$data_for_this_cpd[i] <- "low data"
    
  } else {
    ktcor<- cor.test(x = df$x, y = df$y, method = "kendall")
    dat.test$p_val[i] <- ktcor$p.value
    dat.test$kendall_tau[i] <- ktcor$estimate
    
  }
  
  if (!(is.na(dat.test$p_val[i])|is.na(dat.test$kendall_tau[i]))) {
    if (dat.test$p_val[i] <= 0.05 & dat.test$kendall_tau[i] > 0) { dat.test$trend_with_age[i] <- "Increasing"; dat.test$trend_with_degrad[i] <- "Decreasing" }
    if (dat.test$p_val[i] <= 0.05 & dat.test$kendall_tau[i] < 0) { dat.test$trend_with_age[i] <- "Decreasing"; dat.test$trend_with_degrad[i] <- "Increasing"  }
  }
  print(paste0("Completed ",i))
}

sel.disq <- which(dat.test$data_for_this_cpd == "disqualified") # empty
sel.low <- which(dat.test$data_for_this_cpd == "low data") # 286

length(unique(data_in$cpd_id)) # 8349
length(unique(data_in$cpd_id)) - (length(sel.disq) + length(sel.low) ) # 8063

sel.nonNA <- which(!is.na(dat.test$p_val)) # 8063 applicable tests

# only keep applicable tests; the remainder are likely due to zero replacement:
dat.test <- dat.test[ sel.nonNA, ]


sel.sig <- which(dat.test$p_val <= 0.05) # 3024


summary(dat.test$p_val)
# Min.   1st Qu.    Median      Mean   3rd Qu.      Max. 
# 0.0000052 0.0113463 0.1562389 0.2643100 0.4783756 1.0000000  


hist(dat.test$p_val)

saveRDS(object = dat.test, file = "dat.test.cpp3d-wang-veg-succession-v8c.rds" )
#dat.test <- readRDS("dat.test.cpp3d-wang-veg-succession-v8c.rds")


str(dat.test)
# 'data.frame':	8063 obs. of  6 variables:
# $ cpd              : chr  "cpd25681" "cpd02597" "cpd24620" "cpd00001" ...
# $ data_for_this_cpd: chr  NA NA NA NA ...
# $ p_val            : num  0.36205 0.00846 0.02588 0.01984 0.00331 ...
# $ kendall_tau      : num  0.185 0.535 0.453 -0.473 0.597 ...
# $ trend_with_age   : chr  NA "Increasing" "Increasing" "Decreasing" ...
# $ trend_with_degrad: chr  NA "Decreasing" "Decreasing" "Increasing" ...

sel <- which(is.na(dat.test$p_val)) # empty

dat.test$p_adj_BH <- p.adjust(dat.test$p_val, method = "BH" )
hist(dat.test$p_adj_BH)


# extract sig results

sel.sigBH <- which(dat.test$p_adj_BH <= 0.05) # 2120
dat.test$sigBH <- NA
dat.test$sigBH[sel.sigBH] <- "sig"

sel.sig <- which(dat.test$p_val <= 0.05) # 3024

dat.test.sig <- dat.test[sel.sig, ]

dat.test.sig$minuslog10_p_val <- -log10(dat.test.sig$p_val)
plot(x = dat.test.sig$kendall_tau , y =dat.test.sig$minuslog10_p_val , xlab="Kendall tau", ylab="-log10(P-value)")

sel.sigBH <- which(dat.test.sig$sigBH == "sig")

points(x=dat.test.sig$kendall_tau[sel.sigBH], y=dat.test.sig$minuslog10_p_val[sel.sigBH], col="purple" )
