# [6] "Bases"                    "BioProject"               "BioSample"                "Bytes"                    "center_name (exp)"       
# [11] "Center Name"              "Consent"                  "DATASTORE filetype"       "DATASTORE provider"       "DATASTORE region"        
# [16] "Experiment"               "gender"                   "Instrument"               "Library Name"             "LibraryLayout"           
# [21] "LibrarySelection"         "LibrarySource"            "NATION"                   "Organism"                 "Platform"                
# [26] "ReleaseDate"              "run (run)"                "Sample Name"              "SRA Study"                "total_bases (run)"       
# [31] "Diagnosis"                "non_host_reads"           "fxn_sum_counts"           "group_label"              "sex"      

# Adonis test
set.seed(123)
adonis2(bray ~ group_label + sex , data = sampledf)
# Permutation test for adonis under reduced model
# Terms added sequentially (first to last)
# Permutation: free
# Number of permutations: 999
# 
# adonis2(formula = bray ~ group_label + sex, data = sampledf)
