### identify overlapping CPP trends across these datasets

unique_cpd_trends <- sort( unique( c(dts.sunbad$cpd___trend_degrad,
                                     dts.ami$cpd___trend_degrad,
                                     dts.mason$cpd___trend_degrad,
                                     dts.zuo$cpd___trend_degrad,
                                     dts.wang$cpd___trend_degrad
)) )
length(unique_cpd_trends) # 10103

length( dts.sunbad$cpd___trend_degrad) +
  length(dts.ami$cpd___trend_degrad) + 
  length( dts.mason$cpd___trend_degrad) +
  length( dts.zuo$cpd___trend_degrad) +
  length( dts.wang$cpd___trend_degrad)

# 18780



dts.match.cpd_trend <- data.frame(cpd_trend = unique_cpd_trends, cpd=NA, trend_with_degrad=NA,
                                  cpd_names=NA, cpd_forms=NA, OC_x=NA, HC_y=NA, NC_z=NA, 
                                  trend_degrad__sunbad=NA,
                                  trend_degrad__ami=NA,
                                  trend_degrad__mason=NA,
                                  trend_degrad__zuo=NA,
                                  trend_degrad__wang=NA
)

for (i in 1:length(unique_cpd_trends)) {
  #i<-2
  this_cpd_trend <- unique_cpd_trends[i]
  
  sel.sunbad <- which(dts.sunbad$cpd___trend_degrad == this_cpd_trend)
  sel.ami <- which(dts.ami$cpd___trend_degrad == this_cpd_trend)
  sel.mason <- which(dts.mason$cpd___trend_degrad == this_cpd_trend)
  sel.zuo <- which(dts.zuo$cpd___trend_degrad == this_cpd_trend)
  sel.wang <- which(dts.wang$cpd___trend_degrad == this_cpd_trend)
  
  if (length(sel.sunbad) > 0) {
    dts.match.cpd_trend$trend_degrad__sunbad[i] <- 1
    dts.match.cpd_trend$cpd[i] <- dts.sunbad$cpd[sel.sunbad]
    dts.match.cpd_trend$trend_with_degrad[i] <- dts.sunbad$trend_with_degrad[sel.sunbad]
    dts.match.cpd_trend$cpd_names[i] <- dts.sunbad$cpd_names[sel.sunbad]
    dts.match.cpd_trend$cpd_forms[i] <- dts.sunbad$cpd_forms[sel.sunbad]
    dts.match.cpd_trend$OC_x[i] <- dts.sunbad$OC_x[sel.sunbad]
    dts.match.cpd_trend$HC_y[i] <- dts.sunbad$HC_y[sel.sunbad]
    dts.match.cpd_trend$NC_z[i] <- dts.sunbad$NC_z[sel.sunbad]
  }
  
  if (length(sel.ami) > 0) {
    dts.match.cpd_trend$trend_degrad__ami[i] <- 1
    dts.match.cpd_trend$cpd[i] <- dts.ami$cpd[sel.ami]
    dts.match.cpd_trend$trend_with_degrad[i] <- dts.ami$trend_with_dist[sel.ami]
    dts.match.cpd_trend$cpd_names[i] <- dts.ami$cpd_names[sel.ami]
    dts.match.cpd_trend$cpd_forms[i] <- dts.ami$cpd_forms[sel.ami]
    dts.match.cpd_trend$OC_x[i] <- dts.ami$OC_x[sel.ami]
    dts.match.cpd_trend$HC_y[i] <- dts.ami$HC_y[sel.ami]
    dts.match.cpd_trend$NC_z[i] <- dts.ami$NC_z[sel.ami]
  }
  
  if (length(sel.mason) > 0) {
    dts.match.cpd_trend$trend_degrad__mason[i] <- 1
    dts.match.cpd_trend$cpd[i] <- dts.mason$cpd[sel.mason]
    dts.match.cpd_trend$trend_with_degrad[i] <- dts.mason$trend_with_degrad[sel.mason]
    dts.match.cpd_trend$cpd_names[i] <- dts.mason$cpd_names[sel.mason]
    dts.match.cpd_trend$cpd_forms[i] <- dts.mason$cpd_forms[sel.mason]
    dts.match.cpd_trend$OC_x[i] <- dts.mason$OC_x[sel.mason]
    dts.match.cpd_trend$HC_y[i] <- dts.mason$HC_y[sel.mason]
    dts.match.cpd_trend$NC_z[i] <- dts.mason$NC_z[sel.mason]
  }
  
  if (length(sel.zuo) > 0) {
    dts.match.cpd_trend$trend_degrad__zuo[i] <- 1
    dts.match.cpd_trend$cpd[i] <- dts.zuo$cpd[sel.zuo]
    dts.match.cpd_trend$trend_with_degrad[i] <- dts.zuo$trend_with_degrad[sel.zuo]
    dts.match.cpd_trend$cpd_names[i] <- dts.zuo$cpd_names[sel.zuo]
    dts.match.cpd_trend$cpd_forms[i] <- dts.zuo$cpd_forms[sel.zuo]
    dts.match.cpd_trend$OC_x[i] <- dts.zuo$OC_x[sel.zuo]
    dts.match.cpd_trend$HC_y[i] <- dts.zuo$HC_y[sel.zuo]
    dts.match.cpd_trend$NC_z[i] <- dts.zuo$NC_z[sel.zuo]
  }
  
  if (length(sel.wang) > 0) {
    dts.match.cpd_trend$trend_degrad__wang[i] <- 1
    dts.match.cpd_trend$cpd[i] <- dts.wang$cpd[sel.wang]
    dts.match.cpd_trend$trend_with_degrad[i] <- dts.wang$trend_with_degrad[sel.wang]
    dts.match.cpd_trend$cpd_names[i] <- dts.wang$cpd_names[sel.wang]
    dts.match.cpd_trend$cpd_forms[i] <- dts.wang$cpd_forms[sel.wang]
    dts.match.cpd_trend$OC_x[i] <- dts.wang$OC_x[sel.wang]
