## Post-mining\nrestoration | Planting age (yr) | Kendall's tau ~ Age
this_study <- casestudyname[["postmine"]]
dat <- datset[["postmine"]]
sel <- which(dat$cpd_id == this_cpd)
temp <- dat[sel, ]
head(temp)
x <- temp$ord_group
y <- temp$cpd_rel_abun
# Kendall Tau correlation
ktcor<- cor.test(x = x, y = y, method = "kendall")
ktcor
# Kendall's rank correlation tau
# data:  x and y
# z = -2.9369, p-value = 0.003315
# alternative hypothesis: true tau is not equal to 0
# sample estimates:
#        tau 
# -0.5966396 
test_result <- paste0(this_var,"\nKendall's tau ~ Age\n", "Tau = ",round(ktcor$estimate,3),"\nP = ",round(ktcor$p.value,4))

age_vec <- sort(as.integer(unique(temp$group)))
names(age_vec) <- levels(temp$group)

p <- ggplot(data = temp, aes(x = ord_group, y = cpd_rel_abun))+
  ggtitle( this_study)+
  geom_point()+
  xlab("Planting age (yr)")+ ylab("CPP (%)")+
  geom_smooth(method = "loess", alpha = 0.1)+
  scale_x_continuous(labels= names(age_vec), breaks = age_vec)+
  theme_bw()+
  annotate(geom="text_npc", npcx = "right", npcy = "top", label = test_result, size = 3, lineheight = 0.85)+
  theme(
    panel.grid.major = element_blank(),
    panel.grid.minor = element_blank(),
