sel <- which(dat$cpd_id == this_cpd)
temp <- dat[sel, ]
head(temp)
#x <- temp$cpd_rel_abun[which(temp$group_label == "T2D met-")] # 33
#y <- temp$cpd_rel_abun[which(temp$group_label == "Normal")] # 43
x <- temp$log10_abun[which(temp$group_label == "T2D met-")] # 33
y <- temp$log10_abun[which(temp$group_label == "Normal")] # 43


# Wilcoxon-Mann-Whitney Test
wmw.test <- wilcox.test(x, y, alternative = "less", paired = FALSE) 
wmw.test
# Wilcoxon rank sum exact test
# data:  x and y
# W = 558, p-value = 0.05696
# alternative hypothesis: true location shift is less than 0

test_result <- paste0(this_var,"\nWilcoxon-Mann-Whitney\n", "W = ",wmw.test$statistic,", P = ",round(wmw.test$p.value,3))

p <- ggplot(data = temp, aes(x = group_label, y = log10_abun))+
  #ylim( min(temp$cpd_rel_abun)-0.04, max(temp$cpd_rel_abun))+
  ylim( min(temp$log10_abun), max(temp$log10_abun)+0.3)+
  ggtitle( this_study)+
  geom_violin()+
  geom_boxplot(width = 0.2, alpha = 0.3)+
  geom_jitter(width = 0.1, height =0, alpha = 0.3)+
  xlab("Diagnosis")+ ylab(NULL)+ # ylab("CPP (%)")+
  theme_bw()+
  annotate(geom="text_npc", npcx = "left", npcy = "top", label = test_result, size = 3, lineheight = 0.85)+
  theme(
    panel.grid.major = element_blank(),
    panel.grid.minor = element_blank(),
    #axis.text.x = element_text(size = rel(0.9), angle = 15, hjust=1, vjust=1),
    title = element_text(size = rel(0.9)),
    axis.text.x = element_text(size = rel(1.1)),
    axis.title = element_text(size = rel(0.9))
  )
p

