  subsel <- which(df$sample == this_samp)
  res$sum_rel_abun[i] <- sum(df$cpd_rel_abun[subsel])
  #res$group[i] <- as.character(unique(df$group[subsel]))
  res$group_label[i] <- as.character(unique(df$group_label[subsel]))
  print(paste0("completed ",i))
}
str(res)
# 'data.frame':	15 obs. of  3 variables:
#   $ sample      : chr  "SRR28123688" "SRR28123689" "SRR28123690" "SRR28123691" ...
# $ sum_rel_abun: num  0.1001 0.0997 0.1196 0.1009 0.1389 ...
# $ group_label : chr  "35" "20" "20" "20" ...
unique(res$group_label) #  "35" "20" "5"  "1"  "50"
res$group_label <- factor(res$group_label, levels = levels(df$group_label), ordered = TRUE)
res$age_vec <- as.integer(res$group_label)

# Kendall Tau correlation
ktcor<- cor.test(x = res$age_vec, y = res$sum_rel_abun, method = "kendall")
ktcor
# Kendall's rank correlation tau
# data:  res$age_vec and res$sum_rel_abun
# z = -3.7471, p-value = 0.0001789
# alternative hypothesis: true tau is not equal to 0
# sample estimates:
#        tau 
# -0.7612299 
test_result <- paste0("Tau = ",round(ktcor$estimate,3),"\nP = ",round(ktcor$p.value,5))

age_vec <- sort(unique(res$age_vec))
names(age_vec) <- levels(res$group_label)

p <- ggplot(data = res, aes(x = age_vec, y = sum_rel_abun))+
  geom_point()+
  #xlab("Vegetation age (yr)")+ ylab("Sum CPP (%)")+
  xlab("Vegetation age (yr)")+ ylab(NULL)+
  geom_smooth(method = "loess", alpha = 0.1)+
  scale_x_continuous(labels= names(age_vec), breaks = age_vec)+
  theme_classic()+
  annotate(geom="text_npc", npcx = "right", npcy = "top", label = test_result, size = 3.25, lineheight = 0.85)+
  theme(
    panel.grid.major = element_blank(),
    panel.grid.minor = element_blank(),
    axis.text.x = element_text(size = rel(1.1)),
    #axis.text.x = element_text(size = rel(1), angle = 15, hjust=1, vjust=1),
    axis.title.x = element_text(size = rel(0.9)),
    axis.title.y = element_text(size = rel(1))
    #title = element_text(size = rel(0.8))
  )
p

